import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { FiMail, FiLock, FiEye, FiEyeOff } from 'react-icons/fi'; // ✅ Added proper icons

function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [forgot, setForgot] = useState(false);
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [otpSent, setOtpSent] = useState(false);
  const [otpTimer, setOtpTimer] = useState(15);
  const [showReset, setShowReset] = useState(false);
  const [resetPassword, setResetPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordChanged, setPasswordChanged] = useState(false);
  const [register, setRegister] = useState(false);
  const [fullName, setFullName] = useState('');
  const [showPassword, setShowPassword] = useState(false); // ✅ Added toggle state

  const { login, loading } = useAuth();
  const navigate = useNavigate();

  React.useEffect(() => {
    let interval = null;
    if (forgot && otpSent && otpTimer > 0) {
      interval = setInterval(() => setOtpTimer(t => t - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [forgot, otpSent, otpTimer]);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await login(email, password);
      navigate('/for-you');
    } catch (err) {
      setError(err.message || 'Failed to log in. Please check your credentials.');
    }
  };

  const handleRegister = (e) => {
    e.preventDefault();
    alert('Registered (functionality to be implemented)');
  };

  const handleSendOtp = () => {
    setOtpSent(true);
    setOtpTimer(15);
  };

  const handleOtpInput = (e, idx) => {
    let val = e.target.value.replace(/[^0-9]/g, '').slice(0, 1);
    let next = [...otp];
    next[idx] = val;
    setOtp(next);
    if (val && idx < otp.length - 1) {
      document.getElementById(`otp-field-${idx + 1}`).focus();
    }
  };

  const handleOtpPaste = (e) => {
    let val = e.clipboardData.getData('text').replace(/[^0-9]/g, '').slice(0, 6).split('');
    setOtp(otp.map((_, i) => val[i] || ''));
  };

  const handleReset = (e) => {
    e.preventDefault();
    if (!resetPassword || !confirmPassword) {
      setError('Please fill both fields');
      return;
    }
    if (resetPassword !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    setError('');
    setPasswordChanged(true);
  };

  const styles = {
    loginContainer: {
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '100vh',
      background: '#2196F3',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", "Roboto", sans-serif',
      position: 'relative',
      overflow: 'hidden',
    },
    backgroundAnimation: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: `
        radial-gradient(circle at 20% 80%, rgba(120, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 80% 20%, rgba(255, 119, 198, 0.3) 0%, transparent 50%),
        radial-gradient(circle at 40% 40%, rgba(120, 219, 255, 0.2) 0%, transparent 50%)
      `,
    },
    loginCard: {
      display: 'flex',
      backgroundColor: 'rgba(255, 255, 255, 0.95)',
      backdropFilter: 'blur(20px)',
      borderRadius: '24px',
      boxShadow: '0 25px 50px rgba(0, 0, 0, 0.15)',
      overflow: 'hidden',
      width: '1000px',
      maxWidth: '90%',
      minHeight: '600px',
      border: '1px solid rgba(255, 255, 255, 0.2)',
    },
    loginFormSection: {
      flex: 1,
      padding: '50px',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
    },
    graphicSection: {
      flex: 1,
      background: 'linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%)',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '40px',
      position: 'relative',
      overflow: 'hidden',
    },
    heading: {
      fontSize: '2.8em',
      color: 'transparent',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      WebkitBackgroundClip: 'text',
      backgroundClip: 'text',
      marginBottom: '40px',
      fontWeight: '700',
      textAlign: 'center',
    },
    form: {
      width: '100%',
      display: 'flex',
      flexDirection: 'column',
      gap: '24px',
    },
    inputGroup: {
      position: 'relative',
    },
    input: {
      padding: '18px 20px 18px 60px',
      border: '2px solid rgba(226, 232, 240, 0.8)',
      borderRadius: '16px',
      fontSize: '1em',
      width: '100%',
      boxSizing: 'border-box',
      transition: 'all 0.3s ease',
      backgroundColor: 'rgba(248, 250, 252, 0.8)',
      fontWeight: '500',
    },
    inputIcon: {
      position: 'absolute',
      left: '20px',
      top: '50%',
      transform: 'translateY(-50%)',
      color: '#667eea',
      fontSize: '22px',
    },
    eyeIcon: {
      position: 'absolute',
      right: '18px',
      top: '50%',
      transform: 'translateY(-50%)',
      color: '#667eea',
      fontSize: '22px',
      cursor: 'pointer',
    },
    button: {
      background: '#4e54c8',
      color: 'white',
      padding: '18px',
      border: 'none',
      borderRadius: '16px',
      fontSize: '1.1em',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      width: '100%',
      marginTop: '10px',
      boxShadow: '0 8px 25px rgba(102, 126, 234, 0.4)',
      position: 'relative',
      overflow: 'hidden',
    },
    buttonHover: {
      position: 'absolute',
      top: '0',
      left: '-100%',
      width: '100%',
      height: '100%',
      background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
      transition: 'left 0.5s',
    },
    errorMessage: {
      color: '#ff4d4f',
      textAlign: 'center',
      marginTop: '15px',
      fontWeight: '500',
      fontSize: '0.95em',
    },
  };

  const animationStyles = `
    @keyframes float {
      0%, 100% { transform: translateY(0px) rotate(0deg); }
      50% { transform: translateY(-20px) rotate(180deg); }
    }
  `;

  const userIcon = { icon: '👤' };
  const orbs = [
    { size: '120px', top: '10%', left: '10%', animationDelay: '0s' },
    { size: '80px', top: '70%', left: '80%', animationDelay: '2s' },
    { size: '100px', top: '20%', left: '85%', animationDelay: '4s' },
    { size: '90px', top: '80%', left: '15%', animationDelay: '1s' },
  ];

  if (passwordChanged) {
    return (
      <div style={styles.loginContainer}>
        <div style={{ background: '#E0F7FA', borderRadius: '18px', padding: '40px 20px', textAlign: 'center' }}>
          <div style={{ fontSize: '1.5em', fontWeight: 'bold', marginBottom: '20px' }}>Password Changed Successfully</div>
          <button style={styles.button} onClick={() => setPasswordChanged(false)}>Back to Login</button>
        </div>
      </div>
    );
  }

  return (
    <>
      <style>{animationStyles}</style>
      <div style={styles.loginContainer}>
        <div style={styles.backgroundAnimation} />
        <div style={styles.loginCard}>
          <div style={styles.loginFormSection}>
            <h2 style={styles.heading}>FLOW TRACK</h2>
            <form onSubmit={handleLogin} style={styles.form}>
              {/* ✅ Proper Email Icon */}
              <div style={styles.inputGroup}>
                <FiMail style={styles.inputIcon} />
                <input
                  type="email"
                  placeholder="Email Address"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={styles.input}
                />
              </div>

              {/* ✅ Password with Eye Toggle */}
              <div style={styles.inputGroup}>
                <FiLock style={styles.inputIcon} />
                <input
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={styles.input}
                />
                {showPassword ? (
                  <FiEyeOff
                    style={styles.eyeIcon}
                    onClick={() => setShowPassword(false)}
                    title="Hide Password"
                  />
                ) : (
                  <FiEye
                    style={styles.eyeIcon}
                    onClick={() => setShowPassword(true)}
                    title="Show Password"
                  />
                )}
              </div>

              <button
                type="submit"
                style={styles.button}
                disabled={loading}
              >
                {loading ? 'Signing In...' : 'Sign In'}
              </button>

              {error && <p style={styles.errorMessage}>{error}</p>}
            </form>
          </div>

          <div style={styles.graphicSection}>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
              <div style={{ fontSize: '80px', color: '#667eea' }}>{userIcon.icon}</div>
              <h3 style={{ color: '#2D3748' }}>Welcome Back</h3>
              <p style={{ color: '#4A5568', textAlign: 'center' }}>
                Sign in to access your projects, collaborate with your team,
                and continue tracking your progress seamlessly.
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

export default Login;
